import{_ as a,c as s,o as e,aN as i}from"./chunks/framework.CqA5BTDU.js";const d="/kb/assets/grafana-datasource-prometheus-full-annotated.qJ6LksaF.png",n="/kb/assets/grafana-dashboard-import-datasource-mapping-annotated.fazcJDHN.png",r="/kb/assets/grafana-dashboard-linux-node-real-data-annotated.V3lODA6n.png",o="/kb/assets/grafana-panel-cpu-promql-config-visible-annotated.Bi_YupTG.png",b=JSON.parse('{"title":"Grafana 指标看板","description":"","frontmatter":{},"headers":[],"relativePath":"12.可观测性与监控告警/10-Grafana指标看板.md","filePath":"12.可观测性与监控告警/10-Grafana指标看板.md","lastUpdated":null}'),h={name:"12.可观测性与监控告警/10-Grafana指标看板.md"};function p(l,t,c,k,u,m){return e(),s("div",null,[...t[0]||(t[0]=[i(`<h1 id="grafana-指标看板" tabindex="-1">Grafana 指标看板 <a class="header-anchor" href="#grafana-指标看板" aria-label="Permalink to &quot;Grafana 指标看板&quot;">​</a></h1><p>Grafana 在指标体系里负责连接数据源、查询数据和展示看板。它自己不去抓 Exporter，也不存指标——指标在 Prometheus 的 TSDB 里，Grafana 通过配置好的 Prometheus 数据源执行 PromQL 查询，再把结果用 Time series、Stat、Table 等面板呈现出来。</p><div class="mermaid-diagram" data-mermaid-code="flowchart%20LR%0A%20%20%20%20exporter%5B%22Exporter%20%2F%20%E5%BA%94%E7%94%A8%3Cbr%2F%3E%2Fmetrics%22%5D%20--%3E%20prometheus%5B%22Prometheus%3Cbr%2F%3E%E9%87%87%E9%9B%86%E4%B8%8E%20TSDB%22%5D%0A%20%20%20%20prometheus%20--%3E%20grafana%5B%22Grafana%3Cbr%2F%3E%E6%9F%A5%E8%AF%A2%E4%B8%8E%E7%9C%8B%E6%9D%BF%22%5D%0A%20%20%20%20prometheus%20--%3E%20alert%5B%22%E5%91%8A%E8%AD%A6%E8%A7%84%E5%88%99%3Cbr%2F%3EPromQL%20%E8%AE%A1%E7%AE%97%22%5D%0A"></div><p>排查 Grafana 看板上没数据时，按这个顺序往下查通常效率更高：面板的 PromQL 和时间范围 → Grafana 数据源的 URL 和 Save &amp; test → Prometheus Query 页面执行同一条 PromQL → Prometheus Targets 看 exporter 是否 UP → exporter 到真实服务的连通性。链路上任何一层断，Grafana 页面都没数据。</p><p>Grafana 和 Prometheus 都跑在 <code>mon01</code> 上。Grafana 数据源里填的 <code>http://127.0.0.1:9090</code> 是 Grafana 服务端去访问 Prometheus 的地址，不是浏览器本机访问 Prometheus 的地址。</p><h2 id="安装-grafana" tabindex="-1">安装 Grafana <a class="header-anchor" href="#安装-grafana" aria-label="Permalink to &quot;安装 Grafana&quot;">​</a></h2><p>版本固定为 <code>13.0.1+security-01</code>，通过 Yum 仓库安装：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 实验环境临时关闭 gpgcheck，生产更适合导入并校验 GPG key</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/etc/yum.repos.d/grafana.repo</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;EOF&#39;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">[grafana]</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">name=grafana</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">baseurl=https://rpm.grafana.com</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">repo_gpgcheck=0</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">enabled=1</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">gpgcheck=0</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">EOF</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dnf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -y</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> grafana</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> enable</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --now</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> grafana-server</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> is-active</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> grafana-server</span></span></code></pre></div><p>Grafana 监听在 <code>3000</code> 端口，初始账号 <code>admin/admin</code>。浏览器访问 <code>http://192.168.10.11:3000</code>。</p><h2 id="接入-prometheus-数据源" tabindex="-1">接入 Prometheus 数据源 <a class="header-anchor" href="#接入-prometheus-数据源" aria-label="Permalink to &quot;接入 Prometheus 数据源&quot;">​</a></h2><p>实验用 provisioning 文件固化数据源配置，路径是 <code>/etc/grafana/provisioning/datasources/prometheus.yml</code>：</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">apiVersion</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">datasources</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  - </span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">uid</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">Prometheus</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">Prometheus</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    type</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">prometheus</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    access</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">proxy</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">           # 浏览器请求 Grafana，Grafana 后端去查 Prometheus</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    url</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">http://127.0.0.1:9090</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    isDefault</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    editable</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span></code></pre></div><p>手工创建数据源时，页面路径：<code>Connections → Data sources → Add data source → Prometheus</code>（中文：连接 → 数据源 → 添加数据源 → Prometheus）</p><p>操作步骤：</p><ol><li>进入 <code>Connections → Data sources</code>，点击 <code>Add data source</code></li><li>选择 <code>Prometheus</code></li><li>填写数据源名称、Prometheus server URL、认证方式和 Scrape interval</li><li>点击 <code>Save &amp; test</code></li></ol><p>关键字段：</p><table tabindex="0"><thead><tr><th>字段</th><th>值</th><th>说明</th></tr></thead><tbody><tr><td>Name</td><td><code>Prometheus</code></td><td>数据源名称，Dashboard 导入时用来映射</td></tr><tr><td>Default</td><td>enabled</td><td>作为默认数据源</td></tr><tr><td>Prometheus server URL</td><td><code>http://127.0.0.1:9090</code></td><td>Grafana 服务端访问 Prometheus 的地址</td></tr><tr><td>Authentication</td><td><code>No Authentication</code></td><td>实验环境 Prometheus 未开启认证</td></tr><tr><td>Scrape interval</td><td><code>15s</code></td><td>和 Prometheus 抓取间隔一致</td></tr></tbody></table><p><img src="`+d+`" alt="Grafana Prometheus 数据源字段"></p><p>保存后进入 <code>Explore</code>（中文：探索）选 Prometheus 数据源，执行 <code>sum by (job) (up)</code> 有结果，说明数据源配置成功。</p><p><code>Save &amp; test</code> 失败时，在 <code>mon01</code> 上确认：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Grafana 服务端能否访问到 Prometheus</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://127.0.0.1:9090/-/ready</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 通过 Grafana API 看当前数据源列表</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -u</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> admin:admin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://127.0.0.1:3000/api/datasources</span></span></code></pre></div><p>浏览器能访问 <code>http://192.168.10.11:9090</code> 不代表 <code>http://127.0.0.1:9090</code> 一定能通——两者网络视角完全不同。</p><h2 id="导入-linux-节点大屏" tabindex="-1">导入 Linux 节点大屏 <a class="header-anchor" href="#导入-linux-节点大屏" aria-label="Permalink to &quot;导入 Linux 节点大屏&quot;">​</a></h2><p>实验 Dashboard 文件 <code>grafana-linux-node-overview-lab.json</code> 包含几个基础面板：</p><table tabindex="0"><thead><tr><th>面板</th><th>类型</th><th>用到的 PromQL</th></tr></thead><tbody><tr><td>UP 主机数</td><td>Stat</td><td><code>sum(up{job=&quot;node&quot;})</code></td></tr><tr><td>CPU 使用率</td><td>Time series</td><td>按 instance 聚合的 idle CPU 反算</td></tr><tr><td>Node Exporter 状态</td><td>Table</td><td><code>up{job=&quot;node&quot;}</code> 按 hostname 展示</td></tr><tr><td>内存使用率</td><td>Time series</td><td><code>MemAvailable / MemTotal</code></td></tr></tbody></table><p>导入路径：<code>Dashboards → New → Import</code>（中文：仪表盘 → 新建 → 导入）</p><p>操作步骤：</p><ol><li>进入 <code>Dashboards</code>，点击 <code>New</code>，选择 <code>Import</code></li><li>上传或粘贴 Dashboard JSON</li><li>在 <code>DS_PROMETHEUS</code> 下拉框选当前 Grafana 里的 <code>Prometheus</code> 数据源</li><li>点击 <code>Import</code></li></ol><table tabindex="0"><thead><tr><th>字段</th><th>值</th><th>说明</th></tr></thead><tbody><tr><td>Name</td><td><code>Linux Node Overview Lab</code></td><td>导入后的看板名称</td></tr><tr><td>Folder</td><td><code>Dashboards</code></td><td>看板保存目录</td></tr><tr><td>DS_PROMETHEUS</td><td><code>Prometheus</code></td><td>把 JSON 模板里的数据源变量映射到真实数据源</td></tr></tbody></table><p><img src="`+n+'" alt="Grafana 导入 Dashboard 数据源映射"></p><p>导入后进入看板，时间范围选最近 30 分钟。UP 主机数显示 <code>3</code>，CPU 和内存面板有 <code>mon01</code>、<code>db01</code>、<code>cache01</code> 的数据，说明数据源映射和 PromQL 都能正常工作。</p><p><img src="'+r+`" alt="Grafana Linux 节点大屏真实数据"></p><h2 id="面板-promql-配置" tabindex="-1">面板 PromQL 配置 <a class="header-anchor" href="#面板-promql-配置" aria-label="Permalink to &quot;面板 PromQL 配置&quot;">​</a></h2><p>排查或修改看板时，经常要打开面板编辑器确认 PromQL、Legend 和面板配置。以 CPU 面板为例，编辑路径：<code>Dashboards → Linux Node Overview Lab → CPU 使用率 → Panel menu → Edit</code>（中文：仪表盘 → Linux Node Overview Lab → CPU 使用率 → 面板菜单 → 编辑）</p><p>操作步骤：</p><ol><li>打开 <code>Linux Node Overview Lab</code>，CPU 面板标题处打开面板菜单</li><li>点击 <code>Edit</code> 进入面板编辑器</li><li>在 <code>Queries</code> 区域确认数据源是 <code>Prometheus</code>，切到 <code>Code</code> 模式</li><li>右侧面板配置里确认标题、单位（Percent）和图例</li></ol><table tabindex="0"><thead><tr><th>字段</th><th>值</th><th>说明</th></tr></thead><tbody><tr><td>Visualization</td><td><code>Time series</code></td><td>CPU 合适看趋势</td></tr><tr><td>Data source</td><td><code>Prometheus</code></td><td>查询 Prometheus</td></tr><tr><td>Query</td><td>CPU 使用率 PromQL</td><td>按 <code>instance</code> 聚合</td></tr><tr><td>Legend</td><td><code>{{instance}} CPU</code></td><td>图例保留实例地址</td></tr><tr><td>Unit</td><td><code>Percent</code></td><td>按百分比展示</td></tr></tbody></table><p>CPU 面板使用的表达式：</p><div class="language-promql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">promql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>100 - (</span></span>
<span class="line"><span>  avg by (instance) (</span></span>
<span class="line"><span>    rate(node_cpu_seconds_total{job=&quot;node&quot;,mode=&quot;idle&quot;}[5m])</span></span>
<span class="line"><span>  ) * 100</span></span>
<span class="line"><span>)</span></span></code></pre></div><p><img src="`+o+'" alt="Grafana CPU 面板 PromQL 配置"></p><p>验证：编辑器上方预览区能看到三台实例的曲线，保存后回到看板仍能显示。</p><p>面板没数据时，<code>Query inspector</code> 可以看 Grafana 发给 Prometheus 的请求和返回错误。排查按这几个点依次过：</p><table tabindex="0"><thead><tr><th>检查点</th><th>看什么</th></tr></thead><tbody><tr><td>Data source</td><td>是不是选了 Prometheus</td></tr><tr><td>PromQL</td><td>指标名、标签、聚合维度对不对</td></tr><tr><td>时间范围</td><td>是否覆盖到有数据的时间段</td></tr><tr><td>Legend</td><td>是否保留了定位需要的 instance/hostname</td></tr><tr><td>Unit</td><td>CPU 和内存用 Percent，流量用 bytes/sec</td></tr></tbody></table><p>CPU 面板如果一台机器出了几十条线——说明没做 <code>avg by (instance)</code>，每个 CPU 核心各出一条线。磁盘面板出现很多奇怪挂载点——没有过滤 <code>tmpfs</code> 和 <code>overlay</code>。</p><h2 id="看板组织" tabindex="-1">看板组织 <a class="header-anchor" href="#看板组织" aria-label="Permalink to &quot;看板组织&quot;">​</a></h2><p>按对象拆看板比按技术拆更自然：</p><table tabindex="0"><thead><tr><th>看板</th><th>关注内容</th></tr></thead><tbody><tr><td>Linux 主机</td><td>CPU、内存、磁盘、网络、负载</td></tr><tr><td>Prometheus 自身</td><td>target 数、抓取耗时、规则计算、TSDB 状态</td></tr><tr><td>MySQL</td><td>连接数、QPS、慢查询、锁等待、复制</td></tr><tr><td>Redis</td><td>连接数、内存、命中率、淘汰、慢命令</td></tr><tr><td>Nginx</td><td>活跃连接、请求量、stub_status 可用性</td></tr><tr><td>业务服务</td><td>请求量、错误率、延迟、队列、下游依赖</td></tr></tbody></table><p>主机看板能说明资源状态，但接口超时、数据库慢、缓存命中率下降这些问题，通常还要配合服务指标和日志一起来看。</p><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><table tabindex="0"><thead><tr><th>现象</th><th>常见原因</th><th>先看什么</th></tr></thead><tbody><tr><td>数据源测试失败</td><td>URL 写错、Grafana 到 Prometheus 不通</td><td>在 Grafana 机器上 <code>curl http://127.0.0.1:9090/-/ready</code></td></tr><tr><td>导入后看板空白</td><td>DS_PROMETHEUS 没映射</td><td>回到导入页或 JSON 里看数据源变量</td></tr><tr><td>Explore 有数据，面板没数据</td><td>面板 PromQL、变量或时间范围不对</td><td>打开面板编辑器看查询预览</td></tr><tr><td>某台机器没数据</td><td>对应 target 不在 UP 或标签没匹配</td><td><code>up{instance=&quot;...&quot;}</code> 和 Targets 页面</td></tr><tr><td>CPU 曲线太多</td><td>没按 instance 聚合</td><td><code>avg by (instance)</code></td></tr><tr><td>单位显示奇怪</td><td>Panel unit 没设对</td><td>Percent、bytes/sec、seconds 按指标类型选</td></tr></tbody></table><p>Grafana 是展示层，Prometheus 才是指标来源。看板排查时把 PromQL、数据源、Prometheus Targets 和 exporter 状态放在一起看。</p>',51)])])}const E=a(h,[["render",p]]);export{b as __pageData,E as default};
